import React from "react";

const Experience = () => {
  let experiences = [
    {
      title: "Full Stack Developer",
      startDate: "August 2019",
      endDate: "current",
      companyName: "August 99 Inc. - Canstar Division",
    },
    {
      title: "Full Stack Developer",
      startDate: "August 2019",
      endDate: "current",
      companyName: "August 99 Inc. - Canstar Division",
    },
    {
      title: "32323",
      startDate: "August 2019",
      endDate: "current",
      companyName: "August 99 Inc. - Canstar Division",
    },
    {
      title: "kkkk",
      startDate: "August 2019",
      endDate: "current",
      companyName: "August 99 Inc. - Canstar Division",
    },
  ];

  return (
    <React.Fragment>
      <div className="about-container">
        <div className="row">
          <div className="col-md-12">
            <h2>Experience</h2>
          </div>
        </div>
        <div className="row experience">
          {this.experiences.map((exp) => (
            <div className="col-md-3">{this.exp.title}</div>
          ))}
        </div>
      </div>
    </React.Fragment>
  );
};

export default Experience;
